SELECT 
FROM drones


        AND (
            LOWER(name) LIKE #{query.keywordLike}
            OR LOWER(model) LIKE #{query.keywordLike}
            OR LOWER(manufacturer) LIKE #{query.keywordLike}
            OR LOWER(serial_number) LIKE #{query.keywordLike}
        )


        AND status = #{query.status}


ORDER BY updated_at DESC, id DESC

SELECT COUNT(1)
FROM drones
WHERE serial_number = #{serialNumber}

    AND id != #{excludeId}
